import{_ as a,o as i,c as t,a2 as o}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Extending Autofac","description":"","frontmatter":{},"headers":[],"relativePath":"developer/extending-autofac.md","filePath":"developer/extending-autofac.md","lastUpdated":null}'),n={name:"developer/extending-autofac.md"};function d(r,e,l,s,c,p){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="extending-autofac" tabindex="-1">Extending Autofac <a class="header-anchor" href="#extending-autofac" aria-label="Permalink to &quot;Extending Autofac&quot;">​</a></h1><p>Autofac is designed around explicit boundaries. Add extensions where the existing layer owns the concern.</p><h2 id="add-a-workflow-capability" tabindex="-1">Add a workflow capability <a class="header-anchor" href="#add-a-workflow-capability" aria-label="Permalink to &quot;Add a workflow capability&quot;">​</a></h2><p>Use <code>src/Autofac.Workflows</code> when changing BPMN validation, runtime behavior, step advancement, timers, external events, or runtime mode selection.</p><p>Checklist:</p><ul><li>Add or update validation for any new BPMN extension fields.</li><li>Persist enough state to resume after process restart.</li><li>Include evidence for new runtime behavior.</li><li>Add tests for happy path, invalid input, and resume behavior.</li></ul><h2 id="add-an-agent-tool" tabindex="-1">Add an agent tool <a class="header-anchor" href="#add-an-agent-tool" aria-label="Permalink to &quot;Add an agent tool&quot;">​</a></h2><p>Use <code>src/Autofac.Agents</code> and the Tool Gateway boundary.</p><p>Checklist:</p><ul><li>Define the tool contract clearly.</li><li>Require explicit agent permission.</li><li>Evaluate policy before execution.</li><li>Record invocation and result metadata.</li><li>Redact sensitive inputs and outputs.</li><li>Add tests that prove blocked, escalated, and allowed paths.</li></ul><h2 id="add-an-integration" tabindex="-1">Add an integration <a class="header-anchor" href="#add-an-integration" aria-label="Permalink to &quot;Add an integration&quot;">​</a></h2><p>Use <code>src/Autofac.Integrations</code> for external systems such as source control, planning tools, chat systems, and CI/CD.</p><p>Checklist:</p><ul><li>Keep credentials in the secret store or deployment environment.</li><li>Add readiness checks where operators need them.</li><li>Make operations idempotent where possible.</li><li>Record external identifiers in run evidence.</li><li>Surface retryable versus terminal errors distinctly.</li></ul><h2 id="add-a-sandbox-provider" tabindex="-1">Add a sandbox provider <a class="header-anchor" href="#add-a-sandbox-provider" aria-label="Permalink to &quot;Add a sandbox provider&quot;">​</a></h2><p>Use <code>src/Autofac.Sandboxes</code>.</p><p>Checklist:</p><ul><li>Define provider options and readiness checks.</li><li>Map Autofac sandbox profiles to provider capabilities.</li><li>Enforce filesystem and network expectations.</li><li>Pass only required environment variables and secrets.</li><li>Capture execution logs and exit status for evidence.</li></ul><h2 id="add-storage-behavior" tabindex="-1">Add storage behavior <a class="header-anchor" href="#add-storage-behavior" aria-label="Permalink to &quot;Add storage behavior&quot;">​</a></h2><p>Use <code>src/Autofac.Storage</code> for artifact and blob behavior.</p><p>Checklist:</p><ul><li>Keep artifact identity tied to run id.</li><li>Avoid leaking local paths in public evidence where not needed.</li><li>Support download and retention requirements.</li><li>Add tests for missing objects, overwrite behavior, and provider errors.</li></ul><h2 id="add-web-ui-behavior" tabindex="-1">Add web UI behavior <a class="header-anchor" href="#add-web-ui-behavior" aria-label="Permalink to &quot;Add web UI behavior&quot;">​</a></h2><p>Use <code>web/</code> for product UI changes.</p><p>Checklist:</p><ul><li>Match existing React and Vite patterns.</li><li>Keep operational screens dense and scannable.</li><li>Verify keyboard access for interactive controls.</li><li>Run lint, tests, and build.</li><li>Browser-test the flow with real console and layout checks.</li></ul><h2 id="add-docs-behavior" tabindex="-1">Add docs behavior <a class="header-anchor" href="#add-docs-behavior" aria-label="Permalink to &quot;Add docs behavior&quot;">​</a></h2><p>Use <code>docs.autofac.de/</code> for the public manual site and <code>docs/</code> for raw design or planning material that is not ready for the manual.</p><p>Checklist:</p><ul><li>Keep public docs task-oriented.</li><li>Label enterprise-only capabilities.</li><li>Avoid copying outdated planning statements into the manual.</li><li>Run the docs build and inspect links before publishing.</li></ul>',30)])])}const b=a(n,[["render",d]]);export{h as __pageData,b as default};
